// O(1) — constant, regardless of input size
int getFirst(int[] arr) { return arr[0]; }

// O(log n) — halves the search space each step
int binarySearch(int[] arr, int target) {
    int lo = 0, hi = arr.length - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (arr[mid] == target) return mid;
        if (arr[mid] < target)  lo = mid + 1;
        else                    hi = mid - 1;
    }
    return -1;
}

// O(n) — single pass
int sum(int[] arr) {
    int s = 0;
    for (int x : arr) s += x;
    return s;
}

// O(n²) — nested loops over same input
bool hasDuplicate(int[] arr) {
    for (int i = 0; i < arr.length; i++)
        for (int j = i + 1; j < arr.length; j++)
            if (arr[i] == arr[j]) return true;
    return false;
}
// O(n) alternative: add to HashSet, check contains

// Amortized O(1): ArrayList.add()
// Appending copies array when capacity is exceeded (O(n) resize)
// but resizing doubles capacity, so the cost is amortized O(1) per add

// Classic: factorial (O(n) time, O(n) space — call stack depth = n)
long factorial(int n) {
    if (n <= 1) return 1;           // base case
    return n * factorial(n - 1);   // recursive case
}

// Tree DFS — natural recursive structure
int depth(TreeNode root) {
    if (root == null) return 0;    // base case
    return 1 + Math.max(depth(root.left), depth(root.right));
}

// Convert to iterative when depth is large
int depthIterative(TreeNode root) {
    if (root == null) return 0;
    Deque<TreeNode> stack = new ArrayDeque<>();
    Deque<Integer> depths = new ArrayDeque<>();
    stack.push(root); depths.push(1);
    int maxDepth = 0;
    while (!stack.isEmpty()) {
        TreeNode node = stack.pop();
        int d = depths.pop();
        maxDepth = Math.max(maxDepth, d);
        if (node.left  != null) { stack.push(node.left);  depths.push(d + 1); }
        if (node.right != null) { stack.push(node.right); depths.push(d + 1); }
    }
    return maxDepth;
}
// Same result, no StackOverflowError for deep trees

// Fibonacci: naive O(2^n) — exponential due to repeated subproblems
int fib(int n) {
    if (n <= 1) return n;
    return fib(n-1) + fib(n-2); // fib(5) recomputes fib(3) twice, fib(2) thrice...
}

// Top-down memoization: O(n) time, O(n) space
Map<Integer, Integer> memo = new HashMap<>();
int fibMemo(int n) {
    if (n <= 1) return n;
    if (memo.containsKey(n)) return memo.get(n);
    int result = fibMemo(n-1) + fibMemo(n-2);
    memo.put(n, result);
    return result;
}

// Bottom-up tabulation: O(n) time, O(1) space
int fibDP(int n) {
    if (n <= 1) return n;
    int prev2 = 0, prev1 = 1;
    for (int i = 2; i <= n; i++) {
        int curr = prev1 + prev2;
        prev2 = prev1;
        prev1 = curr;
    }
    return prev1;
}

// Coin change (classic DP)
int coinChange(int[] coins, int amount) {
    int[] dp = new int[amount + 1];
    Arrays.fill(dp, amount + 1);  // fill with 'infinity'
    dp[0] = 0;
    for (int a = 1; a <= amount; a++)
        for (int coin : coins)
            if (coin <= a) dp[a] = Math.min(dp[a], dp[a - coin] + 1);
    return dp[amount] > amount ? -1 : dp[amount];
}

// Arrays.sort — primitives use dual-pivot quicksort (unstable)
int[] nums = {5, 2, 8, 1, 9};
Arrays.sort(nums);              // [1, 2, 5, 8, 9]
Arrays.sort(nums, 1, 4);        // sort subarray [1..3] only

// Arrays.sort — objects use TimSort (stable)
String[] words = {"banana", "apple", "cherry"};
Arrays.sort(words);             // [apple, banana, cherry] natural order
Arrays.sort(words, Comparator.comparingInt(String::length)); // by length

