// Comparable: natural ordering on the class itself
class Version implements Comparable<Version> {
    int major, minor;
    @Override
    public int compareTo(Version other) {
        int c = Integer.compare(this.major, other.major);
        return c != 0 ? c : Integer.compare(this.minor, other.minor);
    }
}

// Standard binary search
int search(int[] arr, int target) {
    int lo = 0, hi = arr.length - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if      (arr[mid] == target) return mid;
        else if (arr[mid] <  target) lo = mid + 1;
        else                         hi = mid - 1;
    }
    return -1;
}

// Lower bound: first index where arr[i] >= target
int lowerBound(int[] arr, int target) {
    int lo = 0, hi = arr.length; // hi = length (exclusive)
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (arr[mid] < target) lo = mid + 1;
        else                   hi = mid;     // not mid-1 !
    }
    return lo; // lo == hi: insertion point
}

// Search in rotated sorted array [4,5,6,7,0,1,2], target=0
int searchRotated(int[] arr, int target) {
    int lo = 0, hi = arr.length - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (arr[mid] == target) return mid;
        if (arr[lo] <= arr[mid]) { // left half sorted
            if (arr[lo] <= target && target < arr[mid]) hi = mid - 1;
            else lo = mid + 1;
        } else {                   // right half sorted
            if (arr[mid] < target && target <= arr[hi]) lo = mid + 1;
            else hi = mid - 1;
        }
    }
    return -1;
}

// Fixed window: max sum of k consecutive elements — O(n)
int maxSum(int[] arr, int k) {
    int windowSum = 0;
    for (int i = 0; i < k; i++) windowSum += arr[i];
    int maxSum = windowSum;
    for (int i = k; i < arr.length; i++) {
        windowSum += arr[i] - arr[i - k]; // slide: add new, remove old
        maxSum = Math.max(maxSum, windowSum);
    }
    return maxSum;
}

// Variable window: longest substring without repeating chars — O(n)
int lengthOfLongestSubstring(String s) {
    Map<Character, Integer> lastSeen = new HashMap<>();
    int maxLen = 0, left = 0;
    for (int right = 0; right < s.length(); right++) {
        char c = s.charAt(right);
        if (lastSeen.containsKey(c) && lastSeen.get(c) >= left) {
            left = lastSeen.get(c) + 1; // shrink window past duplicate
        }
        lastSeen.put(c, right);
        maxLen = Math.max(maxLen, right - left + 1);
    }
    return maxLen;
}

// Two pointers: two-sum in sorted array — O(n)
int[] twoSum(int[] numbers, int target) {
    int left = 0, right = numbers.length - 1;
    while (left < right) {
        int sum = numbers[left] + numbers[right];
        if      (sum == target) return new int[]{left+1, right+1};
        else if (sum <  target) left++;
        else                    right--;
    }
    return new int[]{-1, -1};
}

// BFS — shortest path in unweighted graph
int bfsShortestPath(Map<Integer, List<Integer>> graph, int src, int dst) {
    Queue<Integer> queue = new ArrayDeque<>();
    Set<Integer> visited = new HashSet<>();
    queue.offer(src); visited.add(src);
    int distance = 0;
    while (!queue.isEmpty()) {
        int size = queue.size();
        for (int i = 0; i < size; i++) {
            int node = queue.poll();
            if (node == dst) return distance;
            for (int neighbor : graph.getOrDefault(node, List.of())) {
                if (visited.add(neighbor)) queue.offer(neighbor);
            }
        }
        distance++;
    }
    return -1;
}

// Dijkstra — shortest path in weighted graph
int[] dijkstra(int[][] graph, int n, int src) {
    int[] dist = new int[n];
    Arrays.fill(dist, Integer.MAX_VALUE);
    dist[src] = 0;
    PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
    pq.offer(new int[]{0, src}); // {distance, node}
    while (!pq.isEmpty()) {
        int[] curr = pq.poll();
        int d = curr[0], u = curr[1];
        if (d > dist[u]) continue; // stale entry
        for (int[] edge : getNeighbors(graph, u)) { // {v, weight}
            int v = edge[0], w = edge[1];
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.offer(new int[]{dist[v], v});
            }
        }
    }
    return dist;
}

// Backtracking template
void backtrack(State state, List<Result> results) {
    if (isComplete(state)) {        // base case: valid solution found
        results.add(new Result(state));
        return;
    }
    for (Choice choice : getCandidates(state)) {
        if (!isValid(state, choice)) continue; // prune early
        applyChoice(state, choice);            // choose
        backtrack(state, results);             // explore
        undoChoice(state, choice);             // unchoose
    }
}

// Permutations of [1,2,3]
List<List<Integer>> permutations(int[] nums) {
    List<List<Integer>> results = new ArrayList<>();
    boolean[] used = new boolean[nums.length];
    backtrack(nums, used, new ArrayList<>(), results);
    return results;
}

void backtrack(int[] nums, boolean[] used,
               List<Integer> current, List<List<Integer>> results) {
    if (current.size() == nums.length) {
        results.add(new ArrayList<>(current)); // copy — important!
        return;
    }
    for (int i = 0; i < nums.length; i++) {
        if (used[i]) continue;          // prune: already chosen
        used[i] = true;
        current.add(nums[i]);           // choose
        backtrack(nums, used, current, results);
        current.remove(current.size() - 1); // unchoose
        used[i] = false;
    }
}
